import { useState, useRef, useEffect } from "react";

export default function App() {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const sendMessage = async () => {
    if (!input.trim()) return;

    const userMessage = { role: "user", content: input };
    setMessages((prev) => [...prev, userMessage]);
    setInput("");
    setLoading(true);

    try {
      const response = await fetch("https://mailbot-2e13.onrender.com/chat", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          messages: [[...messages, userMessage].map((m) => [m.role, m.content]).flat()]
        }),
      });

      const data = await response.json();
      setMessages((prev) => [...prev, { role: "assistant", content: data.response }]);
    } catch (error) {
      setMessages((prev) => [...prev, { role: "assistant", content: "Something went wrong. Please try again." }]);
    }

    setLoading(false);
  };

  return (
    <div style={{
      minHeight: "100vh",
      background: "linear-gradient(135deg, #e8f4fd 0%, #f0f4ff 100%)",
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      fontFamily: "-apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif",
      padding: "20px"
    }}>
      <div style={{
        width: "100%",
        maxWidth: "720px",
        height: "85vh",
        background: "white",
        borderRadius: "20px",
        boxShadow: "0 20px 60px rgba(0,0,0,0.1)",
        display: "flex",
        flexDirection: "column",
        overflow: "hidden"
      }}>

        {/* Header */}
        <div style={{
          background: "linear-gradient(135deg, #2563eb, #1e40af)",
          padding: "20px 24px",
          display: "flex",
          alignItems: "center",
          gap: "12px"
        }}>
          <div style={{
            width: "42px",
            height: "42px",
            background: "rgba(255,255,255,0.2)",
            borderRadius: "12px",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontSize: "20px"
          }}>✉️</div>
          <div>
            <h1 style={{ margin: 0, color: "white", fontSize: "18px", fontWeight: "600" }}>MailBot</h1>
            <p style={{ margin: 0, color: "rgba(255,255,255,0.7)", fontSize: "13px" }}>AI Email Assistant</p>
          </div>
          <div style={{
            marginLeft: "auto",
            display: "flex",
            alignItems: "center",
            gap: "6px",
            background: "rgba(255,255,255,0.15)",
            padding: "6px 12px",
            borderRadius: "20px"
          }}>
            <div style={{ width: "8px", height: "8px", background: "#4ade80", borderRadius: "50%" }}></div>
            <span style={{ color: "white", fontSize: "12px" }}>Online</span>
          </div>
        </div>

        {/* Messages */}
        <div style={{
          flex: 1,
          overflowY: "auto",
          padding: "24px",
          display: "flex",
          flexDirection: "column",
          gap: "16px"
        }}>
          {messages.length === 0 && (
            <div style={{
              flex: 1,
              display: "flex",
              flexDirection: "column",
              alignItems: "center",
              justifyContent: "center",
              gap: "16px",
              color: "#94a3b8"
            }}>
              <div style={{ fontSize: "48px" }}>✉️</div>
              <p style={{ margin: 0, fontSize: "16px", fontWeight: "500", color: "#64748b" }}>How can I help you today?</p>
              <div style={{ display: "flex", flexDirection: "column", gap: "8px", width: "100%", maxWidth: "400px" }}>
                {[
                  "Draft an email to my manager asking for time off",
                  "Write a follow-up email to a client",
                  "Draft a professional apology email"
                ].map((suggestion, i) => (
                  <button key={i} onClick={() => setInput(suggestion)} style={{
                    background: "#f8fafc",
                    border: "1px solid #e2e8f0",
                    borderRadius: "10px",
                    padding: "10px 16px",
                    fontSize: "13px",
                    color: "#475569",
                    cursor: "pointer",
                    textAlign: "left"
                  }}>{suggestion}</button>
                ))}
              </div>
            </div>
          )}

          {messages.map((msg, index) => (
            <div key={index} style={{
              display: "flex",
              justifyContent: msg.role === "user" ? "flex-end" : "flex-start",
              gap: "10px",
              alignItems: "flex-end"
            }}>
              {msg.role === "assistant" && (
                <div style={{
                  width: "32px", height: "32px",
                  background: "linear-gradient(135deg, #2563eb, #1e40af)",
                  borderRadius: "10px",
                  display: "flex", alignItems: "center", justifyContent: "center",
                  fontSize: "14px", flexShrink: 0
                }}>✉️</div>
              )}
              <div style={{
                maxWidth: "75%",
                padding: "12px 16px",
                borderRadius: msg.role === "user" ? "18px 18px 4px 18px" : "18px 18px 18px 4px",
                background: msg.role === "user" ? "linear-gradient(135deg, #2563eb, #1e40af)" : "#f1f5f9",
                color: msg.role === "user" ? "white" : "#1e293b",
                fontSize: "14px",
                lineHeight: "1.6",
                whiteSpace: "pre-wrap"
              }}>
                {msg.content}
              </div>
            </div>
          ))}

          {loading && (
            <div style={{ display: "flex", gap: "10px", alignItems: "flex-end" }}>
              <div style={{
                width: "32px", height: "32px",
                background: "linear-gradient(135deg, #2563eb, #1e40af)",
                borderRadius: "10px",
                display: "flex", alignItems: "center", justifyContent: "center",
                fontSize: "14px"
              }}>✉️</div>
              <div style={{
                background: "#f1f5f9",
                borderRadius: "18px 18px 18px 4px",
                padding: "12px 16px",
                display: "flex", gap: "4px", alignItems: "center"
              }}>
                {[0, 1, 2].map(i => (
                  <div key={i} style={{
                    width: "6px", height: "6px",
                    background: "#94a3b8",
                    borderRadius: "50%",
                    animation: `bounce 1.2s ease-in-out ${i * 0.2}s infinite`
                  }}></div>
                ))}
              </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        {/* Input */}
        <div style={{
          padding: "16px 24px",
          borderTop: "1px solid #f1f5f9",
          display: "flex",
          gap: "10px",
          alignItems: "center",
          background: "white"
        }}>
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && sendMessage()}
            placeholder="e.g. Draft an email to my manager asking for Friday off..."
            style={{
              flex: 1,
              border: "1.5px solid #e2e8f0",
              borderRadius: "12px",
              padding: "12px 16px",
              fontSize: "14px",
              outline: "none",
              color: "#1e293b",
              background: "#f8fafc"
            }}
          />
          <button
            onClick={sendMessage}
            disabled={loading}
            style={{
              background: loading ? "#94a3b8" : "linear-gradient(135deg, #2563eb, #1e40af)",
              color: "white",
              border: "none",
              borderRadius: "12px",
              padding: "12px 20px",
              fontSize: "14px",
              fontWeight: "600",
              cursor: loading ? "not-allowed" : "pointer",
              whiteSpace: "nowrap"
            }}
          >
            Send ➤
          </button>
        </div>
      </div>

      <style>{`
        @keyframes bounce {
          0%, 60%, 100% { transform: translateY(0); }
          30% { transform: translateY(-6px); }
        }
      `}</style>
    </div>
  );
}
